File: interview_orchestrator.py  
```python
import logging
import random
from abc import ABC, abstractmethod
from typing import Any, Dict, List, Optional

logger = logging.getLogger(__name__)
logging.basicConfig(level=logging.INFO)


class QuestionGenerator(ABC):
    @abstractmethod
    def generate_question(
        self,
        job_description: str,
        resume_text: str,
        question_type: str,
        context: Optional[str] = None,
    ) -> Optional[Dict[str, Any]]:
        """
        Should return a dict with keys:
          - question_text (str)
          - question_type (str): "technical"/"behavioral"/"follow_up"
          - expected_answer (str)
          - topic (str)
          - difficulty (str)
        """
        pass


class EvaluationService(ABC):
    @abstractmethod
    def evaluate_response(
        self,
        question: str,
        response: str,
        job_description: str,
        candidate_resume: str,
    ) -> Dict[str, Any]:
        """
        Should return a dict with keys:
          - relevance (float)
          - depth (float)
          - confidence (float)
          - technical_accuracy (float)
          - overall_score (float)
          - justification (str)
          - follow_up_required (bool)
        """
        pass


class DatabaseClient(ABC):
    @abstractmethod
    def get_job_details(self, job_id: int) -> Optional[Dict[str, Any]]:
        pass

    @abstractmethod
    def get_candidate_details(self, candidate_id: int) -> Optional[Dict[str, Any]]:
        pass

    @abstractmethod
    def store_question(self, question_data: Dict[str, Any]) -> int:
        pass

    @abstractmethod
    def get_question(self, question_id: int) -> Optional[Dict[str, Any]]:
        pass

    @abstractmethod
    def store_response(self, response_data: Dict[str, Any]) -> int:
        pass

    @abstractmethod
    def store_evaluation(self, eval_data: Dict[str, Any]) -> int:
        pass


class InterviewOrchestrator:
    """
    Manages dynamic Q&A flows, AI calls, session state, and data persistence.
    """

    def __init__(
        self,
        job_id: int,
        candidate_id: int,
        session_id: int,
        question_generator: QuestionGenerator,
        evaluation_service: EvaluationService,
        database_client: DatabaseClient,
        initial_question_count: int = 3,
        technical_question_ratio: float = 0.6,
    ):
        # IDs
        self.job_id = job_id
        self.candidate_id = candidate_id
        self.session_id = session_id

        # Dependencies
        self.qgen = question_generator
        self.eval_service = evaluation_service
        self.db = database_client

        # Config
        self.initial_question_count = initial_question_count
        self.technical_ratio = technical_question_ratio

        # State
        self.question_history: List[int] = []
        self.current_qid: Optional[int] = None
        self.complete = False

        # Load details
        self.job = self.db.get_job_details(job_id)
        self.cand = self.db.get_candidate_details(candidate_id)
        if not self.job or not self.cand:
            raise ValueError("Job or Candidate not found")

        # Context for AI calls
        self.context = {
            "job_description": self.job["description"],
            "resume_text": self.cand["resume_text"],
        }

        # Data for final report
        self.interview_data = {
            "questions": [],
            "responses": [],
            "evaluations": [],
        }

    def _generate_questions(
        self, n: int, qtype: str, context: Optional[str] = None
    ) -> List[Dict[str, Any]]:
        out = []
        for _ in range(n):
            payload = self.qgen.generate_question(
                job_description=self.context["job_description"],
                resume_text=self.context["resume_text"],
                question_type=qtype,
                context=context,
            )
            if not payload:
                logger.warning(f"qgen returned no {qtype}")
                continue
            payload["session_id"] = self.session_id
            qid = self.db.store_question(payload)
            payload["question_id"] = qid
            out.append(payload)
        return out

    def _init_questions(self):
        tech_n = int(self.initial_question_count * self.technical_ratio)
        beh_n = self.initial_question_count - tech_n
        qs = self._generate_questions(tech_n, "technical") + self._generate_questions(beh_n, "behavioral")
        random.shuffle(qs)
        self.question_history = [q["question_id"] for q in qs]
        # Keep the payload in interview_data
        self.interview_data["questions"].extend(qs)

    def start(self) -> Dict[str, Any]:
        if self.complete:
            return {"message": "Already complete"}
        self._init_questions()
        if not self.question_history:
            self.complete = True
            return {"message": "No questions available"}
        return self._pop_next()

    def _pop_next(self) -> Dict[str, Any]:
        self.current_qid = self.question_history.pop(0)
        record = self.db.get_question(self.current_qid)
        if not record:
            logger.error("Question missing in DB")
            return {"message": "Error retrieving question"}
        # Return full metadata
        return {
            "question_id": record["question_id"],
            "question_text": record["question_text"],
            "question_type": record["question_type"],
            "topic": record.get("topic"),
            "difficulty": record.get("difficulty"),
        }

    def next(self) -> Dict[str, Any]:
        if self.complete:
            return {"message": "Interview complete"}
        if not self.question_history:
            self.complete = True
            return {"message": "No more questions"}
        return self._pop_next()

    def submit(self, question_id: int, response: str) -> Dict[str, Any]:
        if self.complete:
            return {"message": "Interview complete"}

        if question_id != self.current_qid:
            return {"error": "Mismatched question_id"}

        # Persist response
        resp_data = {
            "session_id": self.session_id,
            "question_id": question_id,
            "response_text": response,
        }
        rid = self.db.store_response(resp_data)
        resp_data["response_id"] = rid
        self.interview_data["responses"].append(resp_data)

        # Evaluate
        record = self.db.get_question(question_id)
        eval_res = self.eval_service.evaluate_response(
            question=record["question_text"],
            response=response,
            job_description=self.context["job_description"],
            candidate_resume=self.context["resume_text"],
        )
        eval_payload = {
            "session_id": self.session_id,
            "question_id": question_id,
            "category": record["question_type"],
            "score": eval_res.get("overall_score", 0.0),
            "justification": eval_res.get("justification", ""),
        }
        eid = self.db.store_evaluation(eval_payload)
        eval_payload["evaluation_id"] = eid
        self.interview_data["evaluations"].append(eval_payload)

        # Follow‐up?
        if eval_res.get("follow_up_required"):
            fup = self._generate_questions(1, "follow_up", context=response)
            if fup:
                q = fup[0]
                # Prepend
                self.question_history.insert(0, q["question_id"])
                self.interview_data["questions"].append(q)
                return {
                    "evaluation": eval_res,
                    "next_question": {
                        "question_id": q["question_id"],
                        "question_text": q["question_text"],
                        "question_type": q["question_type"],
                    },
                }

        # Otherwise next
        nxt = self.next()
        return {"evaluation": eval_res, "next_question": nxt}

    def get_data(self) -> Dict[str, Any]:
        return self.interview_data

    def end(self):
        self.complete = True
```

