from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Dict
import uvicorn
from interview_orchestrator import (
    InterviewOrchestrator,
    QuestionGenerator,
    EvaluationService,
    DatabaseClient,
)

# Dummy implementations (replace with real services)
class DummyQGen(QuestionGenerator):
    def generate_question(self, job_description, resume_text, question_type, context=None):
        mapping = {
            "technical": "Explain polymorphism.",
            "behavioral": "Tell me about a time you failed.",
            "follow_up": f"Can you expand on '{context[:20]}...'?",
        }
        if question_type not in mapping:
            return None
        return {
            "question_text": mapping[question_type],
            "question_type": question_type,
            "expected_answer": "",
            "topic": "general",
            "difficulty": "medium",
        }

class DummyEval(EvaluationService):
    def evaluate_response(self, question, response, job_description, candidate_resume):
        return {
            "relevance": 0.8,
            "depth": 0.7,
            "confidence": 0.9,
            "technical_accuracy": 0.75,
            "overall_score": 0.8,
            "justification": "Good answer.",
            "follow_up_required": False,
        }

class InMemoryDB(DatabaseClient):
    def __init__(self):
        self.jobs = {123: {"job_id": 123, "description": "Software Eng"}}
        self.cands = {456: {"candidate_id": 456, "resume_text": "Python dev"}}
        self.questions = {}
        self.responses = {}
        self.evals = {}
        self._q = self._r = self._e = 1

    # implement abstract methods similarly to DummyDatabaseClient above
    # omitted for brevity—use the same store/get logic

db = InMemoryDB()
qgen = DummyQGen()
eval_svc = DummyEval()

app = FastAPI(title="Interview Orchestration API")
sessions: Dict[int, InterviewOrchestrator] = {}

class StartReq(BaseModel):
    job_id: int
    candidate_id: int
    session_id: int

class NextReq(BaseModel):
    session_id: int

class SubmitReq(BaseModel):
    session_id: int
    question_id: int
    response: str

@app.post("/start")
def start(body: StartReq):
    if body.session_id in sessions:
        raise HTTPException(400, "Session already exists")
    orchestrator = InterviewOrchestrator(
        job_id=body.job_id,
        candidate_id=body.candidate_id,
        session_id=body.session_id,
        question_generator=qgen,
        evaluation_service=eval_svc,
        database_client=db,
    )
    sessions[body.session_id] = orchestrator
    return orchestrator.start()

@app.post("/next")
def get_next(body: NextReq):
    orch = sessions.get(body.session_id)
    if not orch:
        raise HTTPException(404, "Session not found")
    return orch.next()

@app.post("/submit")
def submit(body: SubmitReq):
    orch = sessions.get(body.session_id)
    if not orch:
        raise HTTPException(404, "Session not found")
    return orch.submit(body.question_id, body.response)

@app.get("/data/{session_id}")
def data(session_id: int):
    orch = sessions.get(session_id)
    if not orch:
        raise HTTPException(404, "Session not found")
    return orch.get_data()

@app.post("/end/{session_id}")
def end(session_id: int):
    orch = sessions.get(session_id)
    if not orch:
        raise HTTPException(404, "Session not found")
    orch.end()
    return {"message": "Interview ended"}

if __name__ == "__main__":
    uvicorn.run("api:app", host="0.0.0.0", port=8000, reload=True)
```

This refactoring:
- Defines clear interfaces (ABCs) for AI services and DB client.  
- Returns rich question metadata.  
- Uses FastAPI with Pydantic models to expose a REST API.  
- Manages orchestrator instances in memory per session.  
- Is async‐ready and production‐oriented (swap Dummy services with real ones, replace InMemoryDB with a real database client).
